SELECT request_id, firm_id
FROM firm_service_requests
WHERE status = 'approved' AND request_date = '2022-02-01';

SELECT version_date, changes
FROM firm_versions
WHERE firm_id = 0;

SELECT COUNT(firm_id) AS firm_count
FROM firm_services
WHERE service_id = 1;

SELECT COUNT(*) AS number_of_service_requests
FROM firm_service_requests
WHERE firm_id = 1;

SELECT firm_id, COUNT(*) AS location_count
FROM firm_locations
GROUP BY firm_id;

SELECT COUNT(service_id) AS service_count
FROM firm_services
WHERE firm_id = 1;
